// Helper: if multiset(arr[..]) == multiset(nums), then arr contains v iff nums contains v
lemma MultisetContainsEquiv(arr: array<int>, nums: seq<int>, v: int)
  requires multiset(arr[..]) == multiset(nums)
  ensures SeqContains(arr[..], v) <==> SeqContains(nums, v)
{
  var s := arr[..];
  if SeqContains(s, v) {
    var i :| 0 <= i < |s| && s[i] == v;
    assert v in multiset(s);
    assert v in multiset(nums);
    assert SeqContains(nums, v) by {
      var j :| j in multiset(nums) && j == v;
      // v is in multiset(nums), so it appears somewhere in nums
      assert multiset(nums)[v] > 0;
      assert v in multiset(nums);
    }
  }
  if SeqContains(nums, v) {
    var i :| 0 <= i < |nums| && nums[i] == v;
    assert v in multiset(nums);
    assert v in multiset(s);
    assert multiset(s)[v] > 0;
  }
  // Need to show: v in multiset(s) ==> SeqContains(s, v)
  // and v in multiset(nums) ==> SeqContains(nums, v)
}

// Helper lemma: element in multiset of seq implies SeqContains
lemma MultisetMemberImpliesSeqContains(s: seq<int>, v: int)
  requires v in multiset(s)
  ensures SeqContains(s, v)
{
  // multiset(s)[v] > 0 means v appears in s
  var i := 0;
  while i < |s|
    invariant 0 <= i <= |s|
    invariant forall j :: 0 <= j < i ==> s[j] != v
  {
    if s[i] == v {
      assert 0 <= i < |s| && s[i] == v;
      return;
    }
    i := i + 1;
  }
  // If we get here, v is not in s, contradicting v in multiset(s)
  assert multiset(s)[v] == 0;
  assert false;
}

