 50→// Count fixed points: positions k in [0,n) where a[k] == k+1
 51→function CountFixed(a: seq<int>, n: int): nat
 52→  requires 0 <= n <= |a|
 53→{
 54→  if n == 0 then 0
 55→  else (if a[n-1] == n then 1 else 0) + CountFixed(a, n-1)
 56→}
