 58→lemma CountFixedUpperBound(a: seq<int>, n: int)
 59→  requires 0 <= n <= |a|
 60→  ensures CountFixed(a, n) <= n
 61→{
 62→  if n > 0 {
 63→    CountFixedUpperBound(a, n - 1);
 64→  }
 65→}
