 67→// If we change position p and nothing else, and p was not fixed and becomes fixed,
 68→// then CountFixed increases by 1 for those positions, and doesn't change for others.
 69→lemma CountFixedSwapEffect(a: seq<int>, b: seq<int>, n: int, p: int, q: int)
 70→  requires |a| == n && |b| == n && 0 <= n
 71→  requires 0 <= p < n && 0 <= q < n && p != q
 72→  requires a[p] != p + 1  // p was not fixed in a
 73→  requires a[q] != q + 1  // q was not fixed in a
 74→  requires b[p] == p + 1  // p is fixed in b
 75→  requires forall k :: 0 <= k < n && k != p && k != q ==> b[k] == a[k]
 76→  ensures CountFixed(b, n) >= CountFixed(a, n) + 1
 77→{
 78→  CountFixedSwapHelper(a, b, n, p, q);
 79→}
