 81→lemma CountFixedSwapHelper(a: seq<int>, b: seq<int>, m: int, p: int, q: int)
 82→  requires |a| == |b| && 0 <= m <= |a|
 83→  requires 0 <= p < |a| && 0 <= q < |a| && p != q
 84→  requires a[p] != p + 1
 85→  requires a[q] != q + 1
 86→  requires b[p] == p + 1
 87→  requires forall k :: 0 <= k < |a| && k != p && k != q ==> b[k] == a[k]
 88→  ensures CountFixed(b, m) >= CountFixed(a, m) + (if p < m then 1 else 0)
 89→  decreases m
 90→{
 91→  if m == 0 {
 92→  } else {
 93→    CountFixedSwapHelper(a, b, m - 1, p, q);
 94→    var pos := m - 1;
 95→    if pos == p {
 96→      // b[p] == p + 1 so b contributes 1, a[p] != p+1 so a contributes 0
 97→      assert (if b[pos] == pos + 1 then 1 else 0) == 1;
 98→      assert (if a[pos] == pos + 1 then 1 else 0) == 0;
 99→    } else if pos == q {
100→      // q might or might not be fixed in b, but wasn't fixed in a
101→      assert (if a[pos] == pos + 1 then 1 else 0) == 0;
102→      // b[q] >= a[q] contribution-wise (a was 0, b is 0 or 1)
103→    } else {
104→      // b[pos] == a[pos], same contribution
105→      assert b[pos] == a[pos];
106→    }
107→  }
108→}
