110→method firstMissingPositive(nums: seq<int>) returns (result: int)
111→  requires |nums| >= 1
112→  ensures  firstMissingPositivePost(nums, result)
113→{
114→    var n := |nums|;
115→    var arr := new int[n];
116→    var i := 0;
117→
118→    while i < n
119→      invariant 0 <= i <= n
120→      invariant forall j :: 0 <= j < i ==> arr[j] == nums[j]
121→    {
122→        arr[i] := nums[i];
123→        i := i + 1;
124→    }
125→
126→    assert arr[..] == nums;
127→    assert multiset(arr[..]) == multiset(nums);
128→
129→    // Phase 2: Cycle sort - place each value v at position v-1
130→    i := 0;
131→    while i < n
132→      invariant 0 <= i <= n
133→      invariant multiset(arr[..]) == multiset(nums)
134→      invariant forall j :: 0 <= j < i ==> (1 <= arr[j] <= n ==> arr[arr[j]-1] == arr[j])
135→      decreases n - i
136→    {
137→        CountFixedUpperBound(arr[..], n);
138→        while 1 <= arr[i] <= n && arr[arr[i] - 1] != arr[i]
139→          invariant 0 <= i < n
140→          invariant multiset(arr[..]) == multiset(nums)
141→          invariant 1 <= arr[i] <= n ==> 0 <= arr[i] - 1 < n
142→          invariant forall j :: 0 <= j < i ==> (1 <= arr[j] <= n ==> arr[arr[j]-1] == arr[j])
143→          invariant CountFixed(arr[..], n) <= n
144→          decreases n - CountFixed(arr[..], n)
145→        {
146→            ghost var old_snap := arr[..];
147→            ghost var old_count := CountFixed(old_snap, n);
148→
149→            var target := arr[i] - 1;
150→            assert target != i by {
151→              if target == i {
152→                assert arr[arr[i] - 1] == arr[i];
153→              }
154→            }
155→            // Before swap facts
156→            assert old_snap[target] != target + 1 by {
157→              // arr[target] != arr[i] (loop condition) and arr[i] = target + 1
158→              assert old_snap[target] != old_snap[i];
159→              assert old_snap[i] == target + 1;
160→            }
161→            assert old_snap[i] != i + 1 by {
162→              assert old_snap[i] == target + 1;
163→              assert target != i;
164→            }
165→
166→            var temp := arr[target];
167→            arr[target] := arr[i];
168→            arr[i] := temp;
169→
170→            ghost var new_snap := arr[..];
171→
172→            // Prove the relationship between new_snap and old_snap
173→            assert new_snap[target] == old_snap[i];
174→            assert new_snap[i] == old_snap[target];
175→            assert forall k :: 0 <= k < n && k != i && k != target ==> new_snap[k] == old_snap[k];
176→            assert new_snap[target] == target + 1;
177→
178→            CountFixedSwapEffect(old_snap, new_snap, n, target, i);
179→            CountFixedUpperBound(new_snap, n);
180→        }
181→        i := i + 1;
182→    }
183→
184→    // Phase 3: Find first missing positive
185→    i := 0;
186→    while i < n
187→      invariant 0 <= i <= n
188→      invariant multiset(arr[..]) == multiset(nums)
189→      invariant forall j :: 0 <= j < i ==> arr[j] == j + 1
190→      decreases n - i
191→    {
192→        if arr[i] != i + 1 {
193→            assert forall j :: 0 <= j < n ==> (1 <= arr[j] <= n ==> arr[arr[j]-1] == arr[j]);
194→            assert !SeqContains(arr[..], i + 1) by {
195→              if SeqContains(arr[..], i + 1) {
196→                var k :| 0 <= k < |arr[..]| && arr[..][k] == i + 1;
197→                assert arr[k] == i + 1;
198→                assert 1 <= arr[k] <= n;
199→                assert arr[arr[k] - 1] == arr[k];
200→                assert arr[i] == i + 1;
201→                assert false;
202→              }
203→            }
204→            MultisetContainsEquiv(arr, nums, i + 1);
205→
206→            forall x | 1 <= x < i + 1
