220→    assert forall j :: 0 <= j < n ==> arr[j] == j + 1;
221→    forall x | 1 <= x <= n
222→      ensures SeqContains(nums, x)
223→    {
224→      assert arr[x-1] == x;
225→      assert 0 <= x - 1 < |arr[..]| && arr[..][x-1] == x;
226→      assert SeqContains(arr[..], x);
227→      MultisetContainsEquiv(arr, nums, x);
228→    }
